// ================= QUERY PARAM =================
const params = new URLSearchParams(window.location.search);
const id = params.get("id");
const data = internshipData[id];

// ================= VALIDATION =================
if (!data) {
  document.body.innerHTML =
    "<h2 style='color:white;text-align:center'>Data not found</h2>";
  throw new Error("Invalid internship ID");
}

// ================= INJECT DATA =================
document.getElementById("detailTitle").textContent = data.title;
document.getElementById("detailDate").textContent = data.date;
document.getElementById("detailDesc").textContent = data.description.trim();
document.getElementById("detailImage").src = data.image;
document.getElementById("downloadCert").href = data.certificate;

// ================= CATEGORY (MULTI CHIP) =================
const categoryContainer = document.getElementById("detailCategories");
categoryContainer.innerHTML = "";

data.category.forEach(cat => {
  const chip = document.createElement("span");
  chip.className = "category-chip";
  chip.textContent = cat;
  categoryContainer.appendChild(chip);
});
